package org.apache.commons.csv;
import static org.apache.commons.csv.Constants.BACKSLASH;
import static org.apache.commons.csv.Constants.COMMA;
import static org.apache.commons.csv.Constants.CR;
import static org.apache.commons.csv.Constants.CRLF;
import static org.apache.commons.csv.Constants.DOUBLE_QUOTE_CHAR;
import static org.apache.commons.csv.Constants.LF;
import static org.apache.commons.csv.Constants.TAB;
import java.io.IOException;
import java.io.Reader;
import java.io.Serializable;
import java.io.StringWriter;
import java.sql.ResultSet;
import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.sql.ResultSetMetaData;
import java.sql.SQLException;

import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    private CSVFormat baseFormat;

    @BeforeEach
    void setUp() {
        baseFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testWithHeader_nullMetaData_returnsFormatWithNullHeader() throws SQLException {
        CSVFormat formatWithHeader = baseFormat.withHeader((ResultSetMetaData) null);
        assertNotNull(formatWithHeader);
        assertNull(formatWithHeader.getHeader());
        // Confirm original format header is unchanged
        assertNull(baseFormat.getHeader());
        assertNotSame(baseFormat, formatWithHeader);
    }

    @Test
    void testWithHeader_metaDataWithNoColumns_returnsFormatWithEmptyHeader() throws SQLException {
        ResultSetMetaData metaData = mock(ResultSetMetaData.class);
        when(metaData.getColumnCount()).thenReturn(0);

        CSVFormat formatWithHeader = baseFormat.withHeader(metaData);

        assertNotNull(formatWithHeader);
        assertNotNull(formatWithHeader.getHeader());
        assertEquals(0, formatWithHeader.getHeader().length);
        assertNotSame(baseFormat, formatWithHeader);
    }

    @Test
    void testWithHeader_metaDataWithColumns_returnsFormatWithHeaderLabels() throws SQLException {
        ResultSetMetaData metaData = mock(ResultSetMetaData.class);
        when(metaData.getColumnCount()).thenReturn(3);
        when(metaData.getColumnLabel(1)).thenReturn("id");
        when(metaData.getColumnLabel(2)).thenReturn("name");
        when(metaData.getColumnLabel(3)).thenReturn("email");

        CSVFormat formatWithHeader = baseFormat.withHeader(metaData);

        assertNotNull(formatWithHeader);
        String[] header = formatWithHeader.getHeader();
        assertNotNull(header);
        assertEquals(3, header.length);
        assertArrayEquals(new String[]{"id", "name", "email"}, header);
        assertNotSame(baseFormat, formatWithHeader);
    }

    @Test
    void testWithHeader_metaDataThrowsSQLException_propagatesException() throws SQLException {
        ResultSetMetaData metaData = mock(ResultSetMetaData.class);
        when(metaData.getColumnCount()).thenThrow(new SQLException("error"));

        SQLException thrown = assertThrows(SQLException.class, () -> baseFormat.withHeader(metaData));
        assertEquals("error", thrown.getMessage());
    }
}
